export const 破廟符 = (bi) => {
    const u = bi.u, k = 2.55;
    const X = (c) => (c - 3.6) * k;
    const Z = (r) => (r - 5.0) * k + 1.0;
    const 線 = (書, 寬 = 0.62) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.65) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.42) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    // 雨冠
    線(p => p.M(X(0.2), Z(5.55)).L(X(7.1), Z(5.48)), 0.8);
    出(p => p.M(X(0.4), Z(5.60)).L(X(0.38), Z(17.38)).C(X(0.37), Z(17.92), X(0.27), Z(18.32), X(0.13), Z(18.59)), 0.7);
    出(p => p.M(X(6.9), Z(5.60)).L(X(6.88), Z(16.57)).C(X(6.9), Z(17.11), X(7.0), Z(17.52), X(7.15), Z(17.79)), 0.7);
    線(p => p.M(X(0.9), Z(6.40)).L(X(2.5), Z(6.36)), 0.55);
    線(p => p.M(X(0.9), Z(7.00)).L(X(2.5), Z(6.96)), 0.55);
    線(p => p.M(X(0.9), Z(7.60)).L(X(2.5), Z(7.56)), 0.55);
    線(p => p.M(X(4.2), Z(6.40)).C(X(5.00), Z(6.24), X(5.40), Z(6.32), X(5.8), Z(6.44)), 0.55);
    線(p => p.M(X(4.2), Z(7.00)).C(X(5.00), Z(6.84), X(5.40), Z(6.92), X(5.8), Z(7.04)), 0.55);
    線(p => p.M(X(4.2), Z(7.60)).C(X(5.00), Z(7.44), X(5.40), Z(7.52), X(5.8), Z(7.64)), 0.55);
    線(p => p.M(X(3.5), Z(5.65)).L(X(3.48), Z(8.20)), 0.6);
    // 厯形（厂內木木底橫）
    線(p => p.M(X(1.2), Z(8.61)).L(X(5.6), Z(8.52)), 0.6);
    出(p => p.M(X(1.35), Z(8.67)).C(X(1.1), Z(10.09), X(0.95), Z(11.57), X(0.9), Z(12.79)), 0.6);
    線(p => p.M(X(2.6), Z(9.15)).L(X(2.58), Z(11.17)), 0.5);
    線(p => p.M(X(1.95), Z(9.96)).L(X(3.25), Z(9.90)), 0.5);
    出(p => p.M(X(2.6), Z(10.22)).L(X(2.10), Z(11.10)), 0.45);
    出(p => p.M(X(2.65), Z(10.22)).L(X(3.15), Z(11.04)), 0.45);
    線(p => p.M(X(4.4), Z(9.15)).L(X(4.38), Z(11.17)), 0.5);
    線(p => p.M(X(3.75), Z(9.96)).L(X(5.05), Z(9.90)), 0.5);
    出(p => p.M(X(4.4), Z(10.22)).L(X(3.90), Z(11.10)), 0.45);
    出(p => p.M(X(4.45), Z(10.22)).L(X(4.95), Z(11.04)), 0.45);
    線(p => p.M(X(2.2), Z(13.06)).L(X(4.8), Z(12.99)), 0.55);
    // 田框翼
    線(p => p.M(X(1.8), Z(13.60)).L(X(1.8), Z(17.65)).L(X(5.6), Z(17.58)).L(X(5.6), Z(13.53)).L(X(1.75), Z(13.60)), 0.6);
    線(p => p.M(X(3.7), Z(13.67)).L(X(3.68), Z(17.58)), 0.55);
    線(p => p.M(X(1.9), Z(15.62)).L(X(5.5), Z(15.57)), 0.5);
    出(p => p.M(X(1.5), Z(14.68)).C(X(1.2), Z(15.09), X(1.2), Z(15.62), X(1.45), Z(15.96)), 0.5);
    出(p => p.M(X(5.9), Z(14.68)).C(X(6.2), Z(15.09), X(6.2), Z(15.62), X(5.95), Z(15.96)), 0.5);
    // 匕曲承中垂
    線(p => p.M(X(2.6), Z(18.19)).C(X(2.3), Z(19.14), X(2.7), Z(19.95), X(3.5), Z(19.95)).C(X(4.1), Z(19.95), X(4.4), Z(19.27), X(4.2), Z(18.73)), 0.6);
    出(p => p.M(X(3.6), Z(20.62)).L(X(3.58), Z(22.24)), 0.62);
    點(3.6, 23.32);
};
